-- 1. Cleaning Companies × Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'cleaning-companies',
  'web-design',
  'Cleaning company websites must serve two fundamentally different audiences with very different needs: domestic clients looking for a regular home cleaner, and commercial clients seeking contract cleaning for offices, retail spaces, or industrial premises. These audiences search differently, evaluate differently, and convert differently. A homeowner wants to know your hourly rate, whether the same cleaner comes each time, and whether you are insured and DBS-checked. A facilities manager wants to know your capacity, your compliance certifications, whether you carry COSHH documentation, and your ability to scale for larger contracts. Most cleaning company websites fail both audiences by presenting a muddled mix of domestic and commercial content that satisfies neither. A purpose-built cleaning company website separates these audiences from the first click, creating dedicated pathways that speak directly to each client type. Domestic clients find pricing transparency, cleaner profiles, and easy recurring booking options. Commercial clients find contract capability, compliance documentation, and a professional tender response process. We build cleaning company websites that convert both audiences by giving each the specific information and reassurance they need to choose your company.',
  'The cleaning industry is intensely competitive and perceived as low-barrier. Dozens of cleaning companies serve every local area, and homeowners often choose based on trust signals rather than cleaning ability. Your website must instantly communicate reliability, professionalism, and trustworthiness. DBS checks, insurance certificates, client testimonials, and transparent pricing are not optional extras; they are the baseline requirements that prevent prospects from clicking back to Google and trying the next company.',
  'We design cleaning company websites around the domestic and commercial split. Domestic pages feature transparent pricing, cleaner introduction profiles, DBS check verification, and recurring booking functionality. Commercial pages present contract capabilities, COSHH compliance, industry-specific cleaning experience, and a formal enquiry process suitable for facilities managers.',
  '[{"title": "Domestic and commercial services competing for attention on the same pages", "description": "A homeowner looking for a weekly two-hour clean does not want to scroll past contract cleaning specifications for warehouses. A facilities manager evaluating commercial cleaning tenders does not want to see domestic hourly rates. When both audiences share the same pages, neither finds the information they need quickly and both question whether your company truly serves their sector."}, {"title": "No trust signals addressing the cleaner-in-your-home concern", "description": "Letting a cleaner into your home requires significant trust. Homeowners need to see DBS check confirmation, public liability insurance, clear policies on key holding and security, and ideally some information about who will actually be cleaning their home. A website that fails to address these trust concerns loses domestic clients to competitors who make their vetting process visible."}, {"title": "No online booking or recurring schedule management", "description": "Domestic cleaning clients expect convenience. If booking a regular clean requires a phone call, email exchange, and manual scheduling, you lose time-poor clients to competitors offering online booking with instant confirmation. The cleaning industry is shifting towards app-like convenience, and websites without booking functionality feel outdated."}]',
  '[{"title": "Split-audience design with dedicated client pathways", "description": "From the homepage, visitors self-select domestic or commercial cleaning. Each pathway presents entirely different content, pricing structures, trust signals, and enquiry processes tailored to that audience. Domestic clients see hourly rates, cleaner profiles, and booking options. Commercial clients see contract specifications, compliance information, and tender response processes."}, {"title": "Trust framework with DBS verification and insurance display", "description": "DBS check status, public liability insurance certificate details, and key holding policies are prominently displayed across the domestic section. Cleaner profiles with first names and areas served personalise the service. For commercial clients, COSHH documentation, method statements, and health and safety certifications provide the compliance assurance facilities managers require."}, {"title": "Online booking with recurring schedule management", "description": "An integrated booking system allows domestic clients to select service type, property size, preferred frequency, and book with instant confirmation. Recurring weekly or fortnightly cleans are set up once and managed through a client portal. Calendar integration shows available slots. This convenience matches the expectations of modern consumers and reduces administrative overhead."}]',
  '[{"question": "Should I separate my domestic and commercial cleaning on the website?", "answer": "Absolutely. Domestic clients and commercial clients have completely different needs, budgets, and decision criteria. Separate sections with distinct messaging, pricing structures, and enquiry processes ensure each audience finds relevant content immediately. A shared approach dilutes your message to both audiences and suggests you are not truly specialised in either sector."}, {"question": "How important is online booking for a cleaning company?", "answer": "Increasingly essential. Domestic cleaning clients expect the same booking convenience they experience with other service apps. Online booking with instant confirmation, recurring schedule options, and easy management captures clients who would not bother with a phone call or email exchange. It also reduces your administrative time spent on manual scheduling."}, {"question": "What trust signals matter most for domestic cleaning clients?", "answer": "DBS checks and insurance are the baseline. Beyond that, cleaner profiles with first names and photos, clear key holding and security policies, transparent pricing with no hidden fees, and genuine client testimonials specific to domestic cleaning. These elements address the fundamental concern of letting someone into your home."}, {"question": "Can the website handle both one-off deep cleans and regular recurring bookings?", "answer": "Yes. The booking system accommodates both. One-off deep cleans, end-of-tenancy cleans, and spring cleans are booked as single appointments with specific requirements. Regular weekly or fortnightly cleans are set up as recurring schedules with a consistent day and time. Both booking types are managed through the same system with different pricing structures."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Cleaning Companies × SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'cleaning-companies',
  'seo',
  'Cleaning services generate some of the most location-specific search traffic in any industry. When someone searches for cleaning services near me, house cleaner Maidstone, or office cleaning Canterbury, they want a company that operates in their area and can start within days. The cleaning sector is intensely competitive in search because the barrier to entry is low and dozens of companies target the same local keywords. Yet within this competition lies enormous opportunity, because most cleaning companies target only the obvious generic terms whilst ignoring the specific, high-converting searches that represent their most profitable work. End of tenancy cleaning, deep cleaning services, commercial kitchen cleaning, post-construction cleaning, carpet cleaning, and oven cleaning each represent distinct service categories with their own search demand and competition levels. A domestic client searching for regular house cleaner Ashford has completely different intent to a letting agent searching for end of tenancy cleaning Kent. Our SEO campaigns for cleaning companies target the full breadth of services across every location you serve, building visibility for both the high-volume general terms and the specific service searches where competition is lower and conversion rates are higher.',
  'For cleaning companies, local search visibility directly translates to recurring revenue. A domestic client who finds you through Google and books a weekly clean represents thousands of pounds in annual revenue from a single search. A commercial client who finds your office cleaning page represents a contract worth tens of thousands annually. Without local SEO, these recurring revenue opportunities go to whatever competitor appears first.',
  'We build SEO around the specific service categories that define commercial and domestic cleaning. Service-specific landing pages target every cleaning type: regular domestic, deep clean, end of tenancy, office cleaning, retail cleaning, industrial cleaning, and specialist services. Location pages target every town in your service area. This granular approach captures traffic across the full spectrum of cleaning searches.',
  '[{"title": "Invisible for high-value commercial cleaning searches", "description": "Office cleaning, retail cleaning, and commercial kitchen cleaning contracts represent your highest-value revenue streams. Yet most cleaning company websites have a single commercial cleaning page that fails to rank for any specific commercial search term. Without dedicated pages for each commercial service type, facilities managers searching for their specific requirement find your competitors instead."}, {"title": "Competing for generic cleaning near me against every local competitor", "description": "The term cleaning services near me is targeted by every cleaning company in your area. Ranking for this one phrase alone is extremely competitive and insufficient. Without broader keyword targeting across specific service types and locations, you depend entirely on a single competitive keyword that may fluctuate and cannot drive the volume of enquiries your business needs."}, {"title": "End of tenancy and deep cleaning searches going to competitors", "description": "End of tenancy cleaning and one-off deep cleaning are high-margin services with excellent search volume. Letting agents and tenants search specifically for these services and choose from the results. If your website has no dedicated, optimised pages for these specific services, this lucrative work flows entirely to competitors who have invested in targeting these terms."}]',
  '[{"title": "Service-specific landing pages for every cleaning category", "description": "Dedicated, optimised pages for regular domestic cleaning, deep cleaning, end of tenancy cleaning, spring cleaning, office cleaning, retail cleaning, industrial cleaning, commercial kitchen cleaning, carpet cleaning, and every specialist service you offer. Each page targets the specific search terms clients use for that service, with relevant content addressing the unique concerns and requirements of each cleaning type."}, {"title": "Location-specific content across your service area", "description": "Landing pages targeting every town and area you serve: cleaning services Maidstone, office cleaning Canterbury, end of tenancy cleaning Ashford, and so on. Each location page features area-specific content and service information rather than duplicate content with only the town name changed. This geographical coverage ensures visibility across your entire operational area."}, {"title": "Google Business Profile and local citation strategy", "description": "Your Google Business Profile is optimised with accurate service categories covering both domestic and commercial cleaning, complete business information, and a review generation strategy targeting satisfied regular clients. Local citation building across cleaning industry directories, local business listings, and trade association directories builds the authority needed for Map Pack visibility."}]',
  '[{"question": "How do I rank for cleaning near me when there is so much competition?", "answer": "You cannot rely on that single phrase alone. We build visibility across dozens of specific search terms: regular house cleaning, deep cleaning, end of tenancy cleaning, office cleaning, and more, each combined with your target locations. This breadth of keyword targeting generates far more total traffic than chasing one competitive generic term, and the specific searches convert at higher rates."}, {"question": "Should I target domestic and commercial cleaning SEO separately?", "answer": "Yes. Domestic and commercial clients use completely different search terms, have different intent, and require different content. Separate pages targeting each market ensure your content is relevant to the searcher and signals to Google that your site has genuine depth in both areas. Mixing domestic and commercial content on shared pages weakens your ranking potential for both."}, {"question": "How important is end of tenancy cleaning for SEO?", "answer": "Very important. End of tenancy cleaning is a high-margin, high-volume search category. Tenants and letting agents search specifically for this service, often with urgency. Dedicated, optimised pages targeting end of tenancy cleaning across your service area can become consistent sources of profitable one-off bookings that supplement your regular recurring cleaning revenue."}, {"question": "Can SEO help me win commercial cleaning contracts?", "answer": "Yes. Many facilities managers begin their search for commercial cleaning providers online. By ranking for specific commercial terms like office cleaning Canterbury or commercial kitchen cleaning Kent, you generate direct enquiries from businesses seeking exactly the services you provide. These organic leads arrive without the cost of tenders or directory commissions."}]'
)
