-- 3. Cleaning Companies × Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'cleaning-companies',
  'lead-capture',
  'Cleaning company enquiries fall into distinct categories that require very different qualification: domestic regular cleaning, one-off domestic cleans, end of tenancy cleaning, and commercial contracts. Each has different pricing structures, different information requirements, and different urgency levels. A letting agent needing end of tenancy cleaning for a property with tenants leaving in five days has extreme urgency. A homeowner looking for a regular weekly cleaner wants to assess compatibility and trustworthiness before committing. A facilities manager evaluating commercial cleaning providers needs to submit specifications and receive a formal proposal. Treating all these enquiries identically with a generic contact form fails every category. Purpose-built lead capture for cleaning companies creates dedicated enquiry paths for each service type. Domestic regular cleaning forms capture property size, room count, pet ownership, cleaning preferences, and preferred schedule. End of tenancy forms capture property size, move-out date, and letting agent requirements. Commercial forms capture premises type, square footage, cleaning frequency, and specific compliance requirements. Each path delivers a qualified brief that enables a fast, informed response.',
  'Speed of response is critical in the cleaning industry. Domestic cleaning clients are often comparing three or four companies simultaneously and will book with whoever responds first with a clear, relevant answer. End of tenancy cleaning is booked under time pressure with immovable deadlines. Commercial clients expect professional, detailed responses. Without structured lead capture, your responses are slower, less informed, and less impressive than competitors who qualify enquiries efficiently.',
  'We build service-specific enquiry flows for each cleaning category. Regular domestic forms capture household details and scheduling preferences. One-off deep clean forms capture specific requirements and urgency. End of tenancy forms include property inventory and move-out dates. Commercial forms capture premises specifications and compliance needs. Each flow enables instant, informed follow-up.',
  '[{"title": "Domestic cleaning enquiries with no household information", "description": "A message saying I need a cleaner please tells you nothing. You do not know the property size, how many rooms, whether they have pets, their preferred day and time, or how frequently they want cleaning. The follow-up call to capture these basics takes fifteen minutes and often goes to voicemail, delaying the booking by days whilst the prospect instructs a faster competitor."}, {"title": "End of tenancy enquiries arriving without critical details", "description": "End of tenancy cleaning is time-critical and specification-dependent. Without knowing the property size, condition, move-out date, and whether an inventory clerk will inspect, you cannot price accurately or confirm availability. Enquiries missing these details require back-and-forth communication that wastes the limited time available before the deadline."}, {"title": "Commercial enquiries not capturing enough detail for proper proposals", "description": "A facilities manager sends a brief message asking about office cleaning. Without premises size, cleaning frequency, specific requirements, out-of-hours access details, and compliance certifications needed, you cannot prepare a professional proposal. The competitor who captures these details upfront and responds with a comprehensive proposal wins the contract."}]',
  '[{"title": "Service-specific enquiry forms for every cleaning category", "description": "Separate forms for regular domestic cleaning, one-off deep cleans, end of tenancy cleaning, and commercial contracts. Each captures the specific information needed to price and respond: property size and layout for domestic, move-out date and inventory requirements for end of tenancy, premises specifications and frequency for commercial. Every enquiry arrives with enough detail for an informed response."}, {"title": "Instant booking capability for standard domestic services", "description": "Regular domestic cleaning and standard deep cleans can be booked directly through the lead capture system. Clients select property size, service type, preferred day and time, and receive instant confirmation with pricing. This captures the time-sensitive clients who want to book immediately rather than wait for a callback. Complex or non-standard requests route to your team for personal response."}, {"title": "Automated acknowledgement with service-specific information", "description": "Each enquiry type triggers a tailored confirmation. Regular cleaning prospects receive information about your vetting process, DBS checks, and what to expect. End of tenancy clients receive a checklist of what the clean covers and what to prepare. Commercial prospects receive your company profile, certifications, and insurance details. This immediate, relevant response builds confidence before your team follows up."}]',
  '[{"question": "Can the lead capture system enable direct booking for domestic cleaning?", "answer": "Yes. Standard domestic cleaning services can be configured for direct online booking with instant confirmation and pricing. Clients select their property size, number of rooms, service frequency, and preferred day. The system shows available slots and confirms the booking immediately. Non-standard requirements or larger properties route to your team for a personalised quote."}, {"question": "How do you handle the urgency of end of tenancy cleaning enquiries?", "answer": "End of tenancy forms capture the move-out date prominently, and urgent enquiries with dates within seven days are flagged for immediate attention. The automated acknowledgement confirms your availability for urgent bookings and sets expectations for response time. Your team receives a priority notification ensuring these time-critical enquiries are handled before routine bookings."}, {"question": "What information should a commercial cleaning enquiry form capture?", "answer": "Premises type and size, number of floors, cleaning frequency required, preferred cleaning hours, specific compliance requirements such as food hygiene or healthcare standards, current cleaning arrangements, contract start date, and any specialist requirements like window cleaning or carpet maintenance. This enables your team to prepare a comprehensive proposal without a preliminary information-gathering visit."}, {"question": "Can the system distinguish between a regular client enquiry and a one-off booking?", "answer": "Yes. The first form step asks about the type of service needed: regular recurring cleaning, one-off deep clean, end of tenancy, or commercial. Each option leads to a tailored form capturing the relevant details. Regular cleaning captures ongoing schedule preferences. One-off cleans capture specific requirements and preferred dates. The distinction ensures appropriate pricing and response."}]'
)
